function generateCommentBody(reports) {
  let totalFailures = reports.filter((r) => r.evaluation?.overall === "failure").length, totalWarnings = reports.filter((r) => r.evaluation?.overall === "warning").length, statusEmoji = totalFailures > 0 ? "\uD83D\uDD34" : totalWarnings > 0 ? "\uD83D\uDFE1" : "\uD83D\uDFE2", statusText = totalFailures > 0 ? `${totalFailures} workload(s) failed` : totalWarnings > 0 ? `${totalWarnings} workload(s) with warnings` : "All passed", header = `## \uD83C\uDF0B SLO Test Results

**Status:** ${statusEmoji} ${reports.length} workload(s) tested • ${statusText}

`, table = `| | Workload | Current | Baseline | Metrics | Report |
|---|----------|---------|----------|---------|--------|
${reports.map((report) => {
    let emoji = report.evaluation?.overall === "failure" ? "\uD83D\uDD34" : report.evaluation?.overall === "warning" ? "\uD83D\uDFE1" : "\uD83D\uDFE2", thresholdInfo = "";
    if (report.evaluation?.failures.length)
      thresholdInfo = ` (${report.evaluation.failures.length} critical)`;
    else if (report.evaluation?.warnings.length)
      thresholdInfo = ` (${report.evaluation.warnings.length} warnings)`;
    let reportLink = report.reportUrl ? `[\uD83D\uDCC4 Report](${report.reportUrl})` : "-";
    return `| ${emoji} | **${report.workload}** | \`${report.currentRef}\` | \`${report.baselineRef}\` | ${report.metricsCount}${thresholdInfo} | ${reportLink} |`;
  }).join(`
`)}
`, footer = `
---
_Generated by [ydb-slo-action](https://github.com/ydb-platform/ydb-slo-action)_`;
  return header + table + footer;
}
async function findExistingComment(pull) {
  let token = getInput("github_token"), octokit = getOctokit(token);
  debug(`Searching for existing SLO comment in PR #${pull}`);
  let { data: comments } = await octokit.rest.issues.listComments({
    issue_number: pull,
    owner: context.repo.owner,
    repo: context.repo.repo
  });
  for (let comment of comments)
    if (comment.body?.includes("\uD83C\uDF0B SLO Test Results"))
      return debug(`Found existing comment: ${comment.id}`), comment.id;
  return null;
}
async function createOrUpdateComment(pull, body) {
  let token = getInput("github_token"), octokit = getOctokit(token), existingId = await findExistingComment(pull);
  if (existingId) {
    info(`Updating existing comment ${existingId}`);
    let { data: data2 } = await octokit.rest.issues.updateComment({
      comment_id: existingId,
      owner: context.repo.owner,
      repo: context.repo.repo,
      body
    });
    return { url: data2.html_url, id: data2.id };
  }
  info("Creating new comment");
  let { data } = await octokit.rest.issues.createComment({
    issue_number: pull,
    owner: context.repo.owner,
    repo: context.repo.repo,
    body
  });
  return { url: data.html_url, id: data.id };
}

